var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS002M0035-04: <color=#ffd34c>【부록-004】 관계자 증언</color>      ","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>……\\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>……\\nCCN No. AS002M0035-04：<color=#ffd34c>【付録-004】 関係者の証言</color>      ","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS002M0035-04: <color=#ffd34c>【Appendix-004】 Contact Testimony</color>      ","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS002M0035-04: <color=#ffd34c>【附錄-004】 相關人士證言</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......다녀왔어.","JPN":"……ただいま。","ENG":"I'm back.","TWN":"……我回來了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"린! 왔구나!","JPN":"リン！おかえりなさい！","ENG":"Lin! You're here!","TWN":"琳！歡迎回來！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"자, 잠깐. 끌어안지 마.","JPN":"ちょ、ちょっと。抱きつかないで。","ENG":"W-wait. Don't hug me.","TWN":"等、等一下。別抱得這麼緊。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"네가 이해해, 린.","JPN":"大目に見てあげて、リン。","ENG":"Try to understand, Lin.","TWN":"妳知道的啊，琳。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"너 걱정하느라고 내내 창 밖만 보고 있었는걸.","JPN":"あなたのことを心配して、ずっと窓の外を見てたんだから。","ENG":"She's been looking out the window, waiting for you.","TWN":"她可是因為擔心妳，一直在看窗外啊。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"하아......","JPN":"ふう……","ENG":"*Sigh*","TWN":"哈啊……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭐야, 지금 왔냐? 멸치? 너 때문에 밥도 못 먹고 있었잖아!","JPN":"なんだよ、やっと来たのか、イワシ？お前のせいで飯も食えてないんだぞ！","ENG":"Huh, you're finally here, Weak Sauce? We were starving because of you!","TWN":"幹嘛，現在才來喔？小魚乾？就為了等妳，我們連飯都沒吃耶！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"조용히 좀 해. 그렇게 먹는 생각만 하니까 군살이 붙지.","JPN":"あなたは黙ってて。そんなふうに食べることばかり考えてるから贅肉がつくんでしょ。","ENG":"Quiet down. You're always thinking of eating. That's why you get so fat.","TWN":"妳安靜點。妳就是只想著吃，才會這麼多贅肉。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭐야?! 대장 걱정시켜 놓고 그러면 내가 봐 줄 줄 아냐!","JPN":"何だと！？隊長に余計な心配させやがって。俺は承知しねえからな！","ENG":"What?! You think I'll take it easy because Cap's worried about you?","TWN":"什麼？！妳讓隊長那麼擔心，以為我會放過妳嗎！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그래? 유진이도 계속 현관을 기웃거리던데, 걱정돼서 그러는 거 아니었어?","JPN":"あら？シロコだって何度も玄関を覗いてたでしょ？リンのことが心配だったんじゃないの？","ENG":"Hmm? Eujin, you were wandering around the door too. Wasn't it because you were worried?","TWN":"是嗎？劉珍也一直在偷看玄關，原來那不是在擔心嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭐, 뭘 실실 쪼개? 누가 네 걱정 따위 했겠냐?","JPN":"な、何ニヤついてたんだよ。別にお前の心配なんかしてねえって。","ENG":"W-what are you grinning about? Who in the world would worry about you?","TWN":"妳、妳幹嘛害羞啦？ 誰會擔心妳啦！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"야, 근데 진짜 별일 없는 거 맞지?","JPN":"おい、本当に大したことなかったんだよな？","ENG":"Hey, but you really don't have anything going on?","TWN":"喂，不過妳真的沒事吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"뭐하러 물어 봐? 걱정 안 한다며?","JPN":"何で聞くの？心配してないんでしょ？","ENG":"Why do you ask? I thought you didn't worry about me.","TWN":"妳問這個幹嘛？妳不是說妳不擔心的嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"돼지.","JPN":"……太っちょのブーちゃん。","ENG":"Pig.","TWN":"蠢豬。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"이 멸치가 진짜!","JPN":"言ったな？このガリガリのイワシ野郎が！","ENG":"You come here, Weak Sauce!","TWN":"妳這個豆芽菜真的是！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"야, 너 잡히면 가만 안 둬!","JPN":"おい、てめえ、捕まえたらタダじゃおかねえからな！","ENG":"Just wait 'till I catch you!","TWN":"可別被我逮到了，我是不會放過妳的！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"얘들아......","JPN":"みんな……","ENG":"Guys...","TWN":"你們……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"그, 그러다가 저번처럼 벽 뚫리면 혼날 텐데......","JPN":"そ、そんなに暴れて、この前みたいに壁に穴を開けたら怒られちゃうよ……","ENG":"W-we'll get into trouble if we make another hole on the wall...","TWN":"不、不要像上次那樣把牆打穿，不然又要被罵了……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그러게.","JPN":"それもそうね。","ENG":"That's true.","TWN":"就是說啊。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"자, 알트 소대 다들 주목!","JPN":"さあ、アルト小隊、ここに注目！","ENG":"Alright, ALT Squad, listen up!","TWN":"阿爾特小隊全員注意！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"린, 문제는 잘 해결된 거야?","JPN":"リン、問題はちゃんと片付いたの？","ENG":"Lin, did you take care of everything?","TWN":"琳，問題順利解決了嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"회사에서도 얘기했지만, 문제라고 할 정도는 아니야.","JPN":"会社でも言ったけど、問題というほどのことじゃないの。","ENG":"I told you back at the company, but there really wasn't any problem.","TWN":"我在公司時也說了，稱不上是什麼問題。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그냥...... 옛날에 <color=#ffd34c>학교</color>에서 있었던 일이 떠올랐어.","JPN":"ただ……昔、<color=#ffd34c>学校</color>であったことを思い出した。","ENG":"It was just... I remembered the things that happened back at the <color=#ffd34c>school</color>.","TWN":"只不過……想起了以前在<color=#ffd34c>學校</color>發生的事情。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"으...... 밥 먹기 전에 식욕 떨어지게......","JPN":"う……飯の前だってのに、食欲の失せる話だな……","ENG":"Ugh... Why would you bring that up before dinner?","TWN":"呃……在吃飯前就沒有食慾了……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"미안해, 린. 그런 일인 줄 알았으면 좀 더 차분히 얘기했을 텐데.","JPN":"ごめんね、リン。気づいてあげられなくて。もう少し落ち着いて話した方がよかったわよね。","ENG":"I'm sorry, Lin. If I knew about that, we could have taken more time to talk about it.","TWN":"抱歉，琳。要是我早點知道有這種事的話，就會好好地跟妳談談了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"아니. 괜찮아. 언제까지 대장한테 응석 부릴 순 없으니까.","JPN":"ううん、平気。いつまでも隊長に甘えるわけにいかないから。","ENG":"No. It's okay. I can't always be pampered by you.","TWN":"不，沒關係。我不能一直向隊長撒嬌。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"그렇지만, 탈출한 뒤로 린이 학교 얘기를 먼저 꺼낸 건 처음이네.","JPN":"でも、脱走してから、リンの方から学校の話を切り出したのは初めてだね。","ENG":"But it's the first time Lin ever talked about the school since we escaped.","TWN":"雖然是這樣說，但在我們逃出去之後，琳還是第一次先提起學校的事情。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"조, 조금 놀랐어.","JPN":"す、少し驚いちゃった……","ENG":"I-I'm a bit surprised.","TWN":"有……有點……嚇了一跳。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"그러고 보니 별일 맞네. 평소엔 그런 일 없었던 것처럼 굴더니.","JPN":"確かに、どういう風の吹き回しだ？いつもは何も覚えてないって言うくせに。","ENG":"That's true. She always acted as if nothing happened there.","TWN":"這麼一說原來還真是有事，明明平時一直在裝沒事一樣。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"오전에 부사장님 지시로 부설 연구소에서 새로 들인 기계를 테스트하러 가 봤어.","JPN":"今日午前中に副社長の指示で、研究所に新規導入されたマシンのテストをしに行ったの。","ENG":"I went to the company lab this morning to test out some new equipment per the Vice President's request.","TWN":"上午接到了副總的指示，要我去附設研究所幫忙測試新的機器。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"기억을 되살리는 기계라던데......","JPN":"記憶を蘇らせるマシンだとか……","ENG":"It's a machine that recalls memories...","TWN":"聽說是讓人恢復記憶的機器……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"기억을?","JPN":"記憶を？","ENG":"Memories?","TWN":"記憶？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"위, 위험했어. 린.","JPN":"き、危険だよ。リン。","ENG":"Th-that's dangerous, Lin.","TWN":"很、很危險的，琳。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"들킬 수 있는지 시험하러 가 본 거야.","JPN":"気づかれる可能性があるか試しに行ったの。","ENG":"I went to see if we would get caught because of it.","TWN":"我只是去試試會不會被發現而已。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"걱정하지 마. 제대로 작동하진 않는 것 같아.","JPN":"安心して。正常には作動しなかったみたいだから。","ENG":"Don't worry though. It didn't work properly.","TWN":"別擔心，機器好像沒有正常運作。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그냥 내 능력이랑 상성이 좋아서 실마리만 떠오른 정도였어.","JPN":"私の能力とは相性が良かったみたいで、記憶を少し思い出す程度で済んだわ。","ENG":"The machine just had good synergy with my ability to bring up a short memory.","TWN":"只不過剛好和我的能力相性比較好，才浮現了一點記憶而已。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"어휴, 이 수수깡 같은 게 진짜!","JPN":"このっ、イワシのくせに生意気だぞ！","ENG":"Geez, you stupid little twig!","TWN":"吼，真是沒用的傢伙！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"무슨 짓이야, 이 야만 멧돼지야!","JPN":"何するのよ、この脳筋イノシシ！","ENG":"What was that for, you savage boar?!","TWN":"幹嘛，妳這隻野蠻的野豬！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"야! 우린 몰라도 대장은 알고 있어야지! 그런 걸 왜 네 마음대로 테스트하러 가?!","JPN":"おいこら！俺たちはともかく隊長には言っとけよな！何勝手にテストなんか受けに行ってんだ！？","ENG":"Hey! Even if you keep it a secret from us, you should've at least told the Cap! Why did you go test that thing on your own?!","TWN":"喂！就算我們不知道，但也應該讓隊長知道啊！妳怎麼可以擅自接受測試？！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"그러다가 너 혼자 추궁 당하기라도 하면, 우린 뭐 모른 척 할 줄 알았냐!","JPN":"もしそれでお前一人だけが追及されたら、俺たちが知らん顔するわけねえだろう？お前一人に背負わせたりしねえっての！","ENG":"If you ended up getting interrogated, did you think we would just ignore you?!","TWN":"到時候妳一個人被追究了，我們能夠裝作不知道嗎！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"미안.","JPN":"ごめん。","ENG":"Sorry.","TWN":"抱歉。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"그렇게 나오......","JPN":"まったく強情な奴……","ENG":"You can't just—","TWN":"就算那樣……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"......뭐?","JPN":"……は？今何つった？","ENG":"What?","TWN":"……嗯？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그렇지만 앞으로도 실수는 하지 않을 거야. 난 저격수니까.","JPN":"でも、これからも狙いを外したりはしない。私は狙撃手だから。","ENG":"But I'm not going to make another mistake. Because I'm a sniper.","TWN":"我不會再犯同樣的錯誤了，畢竟我是狙擊手。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"어......","JPN":"あ……","ENG":"Uh...","TWN":"呃……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"대장, 쟤 이번 주 약 당번 맞지?","JPN":"隊長、こいつ今週の薬当番だったよな？","ENG":"Cap, she's supposed to get our medicine from the hospital this week, right?","TWN":"隊長，但這週的值班是那個人吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"병원에서 검사 받아 봐야 하는 거 아냐?","JPN":"病院で検査受けさせた方がいいんじゃねえの？","ENG":"Shouldn't she have a medical checkup while she's at it?","TWN":"不需要帶她去醫院檢查一下嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"괜찮아.","JPN":"大丈夫よ。","ENG":"It's okay.","TWN":"沒事的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"린은 갈팡질팡할 때가 있어도, 결국 제대로 명중시키는 타입이니까.","JPN":"リンは多少気まぐれだけど、最後には必ず命中させてくれるもの。","ENG":"Lin gets confused sometimes, but she always hits her target in the end.","TWN":"琳雖然會有驚慌失措的時候，但她是最後一定會正確命中目標的類型。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};